topics.syntax:
// Arithmetic
int a = 10 + 5;   // 15
int b = 10 - 3;   // 7
int c = 4 * 2;    // 8
int d = 10 / 3;   // 3
int e = 10 % 3;   // 1

// Assignment
a += 5;  // a = a + 5
b -= 2;  // b = b - 2

// Comparison
bool isEqual = (a == b);
bool isGreater = (a > b);

// Logical
bool bothTrue = (a > 0 && b > 0);
bool eitherTrue = (a > 0 || b < 0);
bool notTrue = !bothTrue;

// Increment / Decrement
int x = 1;
x++;   // x = 2
x--;   // x = 1 again

// Ternary
string result = (a > b) ? "a is bigger" : "b is bigger or equal";

example.code:
int x = 10, y = 3;
Console.WriteLine("Arithmetic:");
Console.WriteLine($"x + y = {x + y}");
Console.WriteLine($"x - y = {x - y}");
Console.WriteLine($"x * y = {x * y}");
Console.WriteLine($"x / y = {x / y}");
Console.WriteLine($"x % y = {x % y}");

Console.WriteLine("\nComparison & Logical:");
bool isEqual = (x == y);
bool bothPositive = (x > 0 && y > 0);
Console.WriteLine($"x == y ? {isEqual}");
Console.WriteLine($"x > 0 && y > 0 ? {bothPositive}");

Console.WriteLine("\nTernary:");
string grade = x > y ? "x is greater" : "y is greater or equal";
Console.WriteLine(grade);

